INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (24001, 1, 1, 1, 321, 40011, "リリ", 2, 0, 125801, "もうすぐ、みなさまに\nお会いできるのですね。\n胸が高鳴ってしまいます……\n");
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (24001, 2, 1, 1, 322, 40011, "クリア", 2, 0, 126001, "初めまして、クリアです♪\nみなさんと一緒に冒険するの\nとっても楽しみにしてます");
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (24001, 3, 1, 1, 323, 40011, "プレシア", 2, 0, 126101, "んーと。\nこれ、あげる。\nはい");
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (24001, 4, 2, 1, 324, 40011, "リリ", 2, 0, 125801, "あらためまして……\n【アルターメイデン】の\nギルドマスター、リリと申します");
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (24001, 5, 2, 1, 325, 40011, "クリア", 2, 0, 126001, "こんにちは、お兄さん♪\n【アルターメイデン】の\nクリアです");
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (24001, 6, 2, 1, 326, 40011, "プレシア", 2, 0, 126101, "お兄。\nきてくれて、うれしい");
